<script setup lang="ts">
import { computed, h, ref } from 'vue'
import { useQuery } from '@tanstack/vue-query'
import { createColumnHelper, FlexRender, getCoreRowModel, useVueTable } from '@tanstack/vue-table'
import { Fingerprint, RefreshCw, Search, ShieldCheck } from 'lucide-vue-next'
import Button from '@/components/ui/Button.vue'
import StatusBadge from '@/components/ui/StatusBadge.vue'
import { getAudit,type AuditEntry } from '@/lib/api'
const search=ref('');const risk=ref('all');const query=useQuery({queryKey:['audit'],queryFn:getAudit,refetchInterval:15000});const filtered=computed(()=>{const needle=search.value.toLowerCase().trim();return(query.data.value??[]).filter(item=>(risk.value==='all'||item.risk===risk.value)&&(!needle||[item.actor_email,item.action,item.target_name,item.resource_type,item.request_id].some(value=>value?.toLowerCase().includes(needle))))});const column=createColumnHelper<AuditEntry>();const columns=[column.accessor('occurred_at',{header:'Data e hora',cell:i=>new Date(i.getValue()).toLocaleString('pt-BR')}),column.accessor('actor_email',{header:'Ator',cell:i=>i.getValue()||'sistema'}),column.accessor('action',{header:'Ação'}),column.accessor('target_name',{header:'Alvo',cell:i=>i.getValue()||'—'}),column.accessor('risk',{header:'Risco',cell:i=>h(StatusBadge,{status:i.getValue()==='critical'?'critical':i.getValue()==='dangerous'?'warning':'info',label:i.getValue()})}),column.accessor('decision',{header:'Decisão',cell:i=>h(StatusBadge,{status:i.getValue()==='allowed'?'healthy':'critical',label:i.getValue()})})];const table=useVueTable({get data(){return filtered.value},columns,getCoreRowModel:getCoreRowModel()})
</script>
<template><div class="mx-auto max-w-[1680px] space-y-5"><header class="flex flex-col justify-between gap-4 md:flex-row md:items-end"><div><div class="flex items-center gap-2 font-mono text-[10px] uppercase tracking-wider text-signal"><ShieldCheck class="h-3.5 w-3.5"/>Evidência encadeada por hash</div><h1 class="mt-3 text-3xl font-semibold tracking-tight">Trilha de auditoria</h1><p class="mt-2 text-sm text-muted">Decisões, autenticações e mutações registradas em ordem verificável.</p></div><Button variant="outline" :disabled="query.isFetching.value" @click="query.refetch()"><RefreshCw :class="['h-4 w-4',query.isFetching.value&&'animate-spin']"/>Atualizar</Button></header><section class="flex flex-col gap-3 rounded-xl border border-line bg-panel/45 p-3 sm:flex-row"><label class="flex h-10 flex-1 items-center gap-2 rounded-lg border border-line bg-slate-950/50 px-3"><Search class="h-4 w-4 text-muted"/><input v-model="search" class="min-w-0 flex-1 bg-transparent text-xs outline-none placeholder:text-muted" placeholder="Buscar ator, ação, alvo ou ID da requisição"/></label><select v-model="risk" class="h-10 rounded-lg border border-line bg-slate-950/60 px-3 text-xs text-slate-300 outline-none"><option value="all">Todos os riscos</option><option value="safe">Seguro</option><option value="dangerous">Perigoso</option><option value="critical">Crítico</option></select></section><div v-if="query.isError.value" class="rounded-xl border border-danger/20 bg-danger/5 p-4 text-sm text-danger">Não foi possível carregar o histórico de auditoria.</div><section v-else class="overflow-hidden rounded-xl border border-line bg-panel/65"><div class="overflow-x-auto"><table class="w-full min-w-[900px] text-left"><thead class="border-b border-line bg-slate-950/35 font-mono text-[9px] uppercase tracking-[.16em] text-muted"><tr v-for="group in table.getHeaderGroups()" :key="group.id"><th v-for="header in group.headers" :key="header.id" class="px-4 py-3"><FlexRender :render="header.column.columnDef.header" :props="header.getContext()"/></th></tr></thead><tbody class="divide-y divide-line/60"><tr v-for="row in table.getRowModel().rows" :key="row.id" class="text-xs text-slate-300 transition-colors hover:bg-white/[.02]" :title="`request ${row.original.request_id||'n/a'} · hash ${row.original.event_hash}`"><td v-for="cell in row.getVisibleCells()" :key="cell.id" class="px-4 py-3.5"><FlexRender :render="cell.column.columnDef.cell" :props="cell.getContext()"/></td></tr></tbody></table><div v-if="query.isLoading.value" class="grid min-h-64 place-items-center"><div class="h-8 w-8 animate-spin rounded-full border-2 border-line border-t-signal"/></div><div v-else-if="!filtered.length" class="grid min-h-64 place-items-center text-center"><div><Fingerprint class="mx-auto h-7 w-7 text-muted"/><p class="mt-3 text-sm text-muted">Nenhum evento corresponde aos filtros.</p></div></div></div><footer class="flex items-center justify-between border-t border-line px-4 py-3 font-mono text-[9px] uppercase tracking-wider text-muted"><span>{{filtered.length}} eventos visíveis</span><span>Cadeia de evidências SHA-256</span></footer></section></div></template>
